AND ( UPPER(e.emp_id) LIKE TRIM(UPPER('%' || #{searchKeyword} || '%')) OR UPPER(e.emp_name) LIKE TRIM(UPPER('%' || #{searchKeyword} || '%')) OR UPPER(d.dname) LIKE TRIM(UPPER('%' || #{searchKeyword} || '%')) )

SELECT * FROM ( SELECT ROWNUM RN, A.* FROM ( SELECT e.emp_id AS empId, e.emp_name AS empName, e.emp_pw AS empPw, e.emp_tel AS empTel, e.emp_email AS empEmail, e.emp_deptno AS empDeptno, d.dname AS deptName, e.emp_auth AS empAuth, e.emp_first AS empFirst, e.emp_inoffice AS empInOffice, e.emp_hiredate AS empHiredate FROM emp e LEFT JOIN dept d ON e.emp_deptno = d.deptno WHERE e.emp_inoffice != 99
AND e.emp_deptno IN
#{deptno}
AND e.emp_auth = #{adminDTO.searchAuth}
AND e.emp_inoffice = #{adminDTO.searchStatus}
AND ( UPPER(e.emp_id) LIKE TRIM(UPPER('%' || #{adminDTO.searchKeyword} || '%')) OR UPPER(e.emp_name) LIKE TRIM(UPPER('%' || #{adminDTO.searchKeyword} || '%')) OR UPPER(d.dname) LIKE TRIM(UPPER('%' || #{adminDTO.searchKeyword} || '%')) )
ORDER BY e.emp_id DESC ) A ) WHERE RN BETWEEN #{page.startRow} AND #{page.endRow}

